python3 << 'EOF'
# Let's check ResponseError's API by using reflection in a simple C# script
import subprocess
script = """
using System;
using System.Reflection;
var asm = Assembly.LoadFrom("/home/runner/.nuget/packages/azure.core/1.46.1/lib/net8.0/Azure.Core.dll");
var type = asm.GetType("Azure.ResponseError");
Console.WriteLine("ResponseError implements:");
foreach (var iface in type.GetInterfaces())
    Console.WriteLine($"  {iface}");
Console.WriteLine("\\nPublic properties:");
foreach (var prop in type.GetProperties(BindingFlags.Public | BindingFlags.Instance))
    Console.WriteLine($"  {prop.PropertyType.Name} {prop.Name}");
Console.WriteLine("\\nPublic constructors:");
foreach (var ctor in type.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
    Console.WriteLine($"  ({string.Join(", ", Array.ConvertAll(ctor.GetParameters(), p => $"{p.ParameterType.Name} {p.Name}"))})");
"""
# Write a quick program
import os, tempfile
with tempfile.TemporaryDirectory() as td:
    with open(os.path.join(td, "Program.cs"), "w") as f:
        f.write(script)
    with open(os.path.join(td, "check.csproj"), "w") as f:
        f.write("""<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup><OutputType>Exe</OutputType><TargetFramework>net9.0</TargetFramework></PropertyGroup>
  <ItemGroup><PackageReference Include="Azure.Core" Version="1.46.1" /></ItemGroup>
</Project>""")
    r = subprocess.run(["dotnet", "run", "--project", os.path.join(td, "check.csproj")], 
                       capture_output=True, text=True, timeout=60)
    print(r.stdout)
    if r.stderr:
        print("STDERR:", r.stderr[:500])
EOF

